// Enable deep-sky object textures
StelSkyLayerMgr.setFlagShow(true);

// Disable all sky layer images
StelSkyLayerMgr.setFlagShow(false);

// Read current state (alternative method)
var visible = core.getStelProperty('StelSkyLayerMgr.flagShow');

// Alternative method (recommended):
var visible = core.getStelProperty('StelSkyLayerMgr.flagShow');
core.debug("Sky layers visible: " + visible);

// Load a sky image from a JSON description file
var key = StelSkyLayerMgr.insertSkyImage("https://example.com/sky_image.json", "dss_layer", true);

// Load a local image with a custom key
var key2 = StelSkyLayerMgr.insertSkyImage("file:///path/to/image.json", "custom_layer");

// Load with texture reduction for performance
var key3 = StelSkyLayerMgr.insertSkyImage("https://example.com/high_res.json", "hd_layer", true, 2);

// Load an image in equatorial coordinates (J2000)
StelSkyLayerMgr.loadSkyImage("myNebula", "nebula.png",
    83.5, -22.0,  // top-left
    83.5, -23.0,  // bottom-left
    84.5, -23.0,  // bottom-right
    84.5, -22.0,  // top-right
    2.5, 14, true, 0);

// Load an image in Alt/Az coordinates (fixed to the horizon)
StelSkyLayerMgr.loadSkyImage("horizonImg", "horizon.jpg",
    0, 0, 0, 30, 90, 30, 90, 0,
    2.5, 14, true, 3);

// Remove a specific layer
StelSkyLayerMgr.removeSkyLayer("my_layer");

// Remove all script-added layers
StelSkyLayerMgr.removeSkyLayer("*");

// Show a sky layer
StelSkyLayerMgr.showLayer("my_layer", true);

// Hide a sky layer
StelSkyLayerMgr.showLayer("dss_layer", false);

if (StelSkyLayerMgr.getShowLayer("my_layer")) {
    core.debug("Layer is visible");
} else {
    StelSkyLayerMgr.showLayer("my_layer", true);
}

var keys = StelSkyLayerMgr.getAllKeys();
core.debug("Layer keys: " + keys.join(", "));

// Iterate through all layers
for (var i = 0; i < keys.length; i++) {
    core.debug("Layer " + i + ": " + keys[i]);
}

// Reload DSO textures (e.g., after changing settings)
StelSkyLayerMgr.loadCollection();

// Reload with reduced texture size for performance
StelSkyLayerMgr.loadCollection(2);
